{
    crate::helpers::unary_f16_op(input, f32::sqrt)
}

/// Elementwise cube root for f16 arrays via f32 promotion.
#[cfg(feature = "f16")]
pub fn cbrt_f16<D>(input: &Array<half::f16, D>) -> FerrumResult<Array<half::f16, D>>
where
