        )
        .unwrap();
        let vals = eigvalsh(&a).unwrap();
        let vs = vals.as_slice().unwrap();
        // Should be sorted nondecreasing
        assert!(vs[0] <= vs[1]);
        assert!(vs[1] <= vs[2]);
    }

