    use crate::products::einsum::parser::parse_subscripts;

    #[test]
    fn trace_contraction() {
        // einsum("ii->i", a) where a is 3x3
        let a = Array::<f64, IxDyn>::from_vec(
            IxDyn::new(&[3, 3]),
