        let a = Array::<f64, IxDyn>::from_vec(IxDyn::new(&[3]), vec![1.0, 2.0, 3.0]).unwrap();
        let b = Array::<f64, IxDyn>::from_vec(IxDyn::new(&[3]), vec![4.0, 5.0, 6.0]).unwrap();
        let result = vdot(&a, &b).unwrap();
        assert!((result - 32.0).abs() < 1e-10);
    }

